Here's a complete example with both `DataRow` and `DynamicData` approaches:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // --- DataRow: best for simple inline values ---

    [TestMethod]
    [DataRow(1, 10.00, 10.00)]
    [DataRow(5, 3.50, 17.50)]
    [DataRow(0, 99.99, 0.00)]
    [DataRow(100, 0.01, 1.00)]
    public void CalculateTotal_ReturnsExpected(int quantity, double unitPrice, double expected)
    {
        var result = _calculator.CalculateTotal(quantity, (decimal)unitPrice);
        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(100.00, 0.10, 90.00, DisplayName = "10% off $100")]
    [DataRow(50.00, 0.25, 37.50, DisplayName = "25% off $50")]
    [DataRow(200.00, 0.00, 200.00, DisplayName = "No discount")]
    [DataRow(80.00, 1.00, 0.00, DisplayName = "100% discount")]
    public void ApplyDiscount_ReturnsExpected(double price, double discount, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discount);
        Assert.AreEqual((decimal)expected, result);
    }

    // --- DynamicData: best for complex objects or computed test cases ---

    [TestMethod]
    [DynamicData(nameof(BulkDiscountCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_BulkScenarios(decimal price, decimal discount, decimal expected, string scenario)
    {
        var result = _calculator.ApplyDiscount(price, discount);
        Assert.AreEqual(expected, result, $"Failed for: {scenario}");
    }

    private static IEnumerable<object[]> BulkDiscountCases()
    {
        yield return new object[] { 1000m, 0.15m, 850m, "Bulk 15% off" };
        yield return new object[] { 499.99m, 0.05m, 474.9905m, "Small bulk 5%" };
        yield return new object[] { 0m, 0.50m, 0m, "Zero price with discount" };
    }

    // --- DynamicData with property source ---

    [TestMethod]
    [DynamicData(nameof(EdgeCases), DynamicDataSourceType.Property)]
    public void CalculateTotal_EdgeCases(int quantity, decimal unitPrice, decimal expected)
    {
        var result = _calculator.CalculateTotal(quantity, unitPrice);
        Assert.AreEqual(expected, result);
    }

    private static IEnumerable<object[]> EdgeCases => new[]
    {
        new object[] { int.MaxValue, 0m, 0m },
        new object[] { 1, decimal.MaxValue, decimal.MaxValue },
        new object[] { 1, 0.001m, 0.001m },
    };

    // --- Validation tests ---

    [TestMethod]
    [DataRow(-1, 10.00)]
    [DataRow(1, -5.00)]
    public void CalculateTotal_InvalidInputs_Throws(int quantity, double unitPrice)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(quantity, (decimal)unitPrice));
    }

    [TestMethod]
    [DataRow(100.00, -0.01)]
    [DataRow(100.00, 1.01)]
    public void ApplyDiscount_InvalidRate_Throws(double price, double discount)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount((decimal)price, (decimal)discount));
    }
}
```

**Key best practices shown:**

| Technique | When to use |
|-----------|-------------|
| `[DataRow]` | Simple primitives, few params |
| `[DynamicData(...Method)]` | Complex objects, computed values |
| `[DynamicData(...Property)]` | Static datasets shared across tests |
| `DisplayName` | Readable test explorer names |

**Notes:**
- `DataRow` only supports compile-time constants (no `decimal` literals — use `double` and cast)
- `DynamicData` methods/properties must be `static` and return `IEnumerable<object[]>`
- One assertion per test method keeps failures clear
- Use `[TestInitialize]` over constructors for setup
